import React from 'react';

function RoboticCore() {
    return (
        <div className="glass-card robotic-core-container" style={{
            height: '400px',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            position: 'relative',
            overflow: 'hidden',
            background: 'rgba(0, 0, 0, 0.4)',
            border: '1px solid rgba(0, 210, 255, 0.15)',
            marginBottom: '40px'
        }}>
            {/* Background Grid for depth */}
            <div style={{
                position: 'absolute',
                width: '200%',
                height: '200%',
                background: 'radial-gradient(circle, rgba(0, 210, 255, 0.05) 1px, transparent 1px)',
                backgroundSize: '40px 40px',
                transform: 'rotateX(60deg) translateY(-50%)',
                opacity: 0.3,
                pointerEvents: 'none'
            }}></div>

            {/* Main Orbital System */}
            <div className="orbital-system">
                {/* Central Robotic Orb */}
                <div className="central-orb">
                    <div className="orb-inner"></div>
                    <div className="orb-ring ring-1"></div>
                    <div className="orb-ring ring-2"></div>
                </div>

                {/* Orbiting Cubes */}
                <div className="cube-orbit orbit-x">
                    <div className="dummy-cube"></div>
                </div>
                <div className="cube-orbit orbit-y">
                    <div className="dummy-cube"></div>
                </div>
                <div className="cube-orbit orbit-z">
                    <div className="dummy-cube"></div>
                </div>
            </div>

            {/* System Status Readouts */}
            <div style={{
                position: 'absolute',
                top: '20px',
                left: '20px',
                fontFamily: 'var(--terminal-font)',
                fontSize: '0.65rem',
                color: 'var(--robotic-blue)',
                letterSpacing: '1px',
                opacity: 0.8
            }}>
                [CORE_STATUS: STABLE] <br />
                [HARMONIC_FREQ: 432_Hz] <br />
                [DIAGNOSTIC_UPLINK: ACTIVE]
            </div>

            <style>{`
        .robotic-core-container {
          perspective: 1000px;
        }

        .orbital-system {
          position: relative;
          width: 0;
          height: 0;
          transform-style: preserve-3d;
          animation: globalRotate 20s linear infinite;
        }

        .central-orb {
          position: absolute;
          width: 60px;
          height: 60px;
          background: var(--robotic-blue);
          border-radius: 50%;
          transform: translate(-50%, -50%);
          box-shadow: 0 0 50px var(--robotic-blue);
          z-index: 10;
        }

        .orb-inner {
          position: absolute;
          width: 100%;
          height: 100%;
          border-radius: 50%;
          background: radial-gradient(circle at 30% 30%, #fff, transparent);
          opacity: 0.5;
        }

        .orb-ring {
          position: absolute;
          top: 50%;
          left: 50%;
          border: 1px solid rgba(0, 210, 255, 0.4);
          border-radius: 50%;
          transform: translate(-50%, -50%);
        }

        .ring-1 { width: 100px; height: 100px; animation: ringRotate 4s linear infinite; }
        .ring-2 { width: 140px; height: 140px; animation: ringRotate 6s linear reverse infinite; border-style: dashed; }

        .cube-orbit {
          position: absolute;
          top: 0;
          left: 0;
          width: 300px;
          height: 300px;
          border-radius: 50%;
          transform: translate(-50%, -50%);
          transform-style: preserve-3d;
        }

        .orbit-x { transform: translate(-50%, -50%) rotateX(75deg); animation: orbitX 8s linear infinite; }
        .orbit-y { transform: translate(-50%, -50%) rotateY(75deg); animation: orbitY 12s linear infinite; }
        .orbit-z { transform: translate(-50%, -50%) rotateZ(75deg); animation: orbitZ 10s linear infinite; }

        .dummy-cube {
          position: absolute;
          top: 0;
          left: 50%;
          width: 20px;
          height: 20px;
          background: #333;
          border: 1px solid var(--robotic-blue);
          transform-style: preserve-3d;
          transform: translateX(-50%) rotateY(45deg);
          box-shadow: 0 0 10px rgba(0, 210, 255, 0.3);
        }

        .dummy-cube::before, .dummy-cube::after {
          content: '';
          position: absolute;
          width: 100%;
          height: 100%;
          background: inherit;
          border: inherit;
        }
        .dummy-cube::before { transform: rotateX(90deg); top: -50%; }
        .dummy-cube::after { transform: rotateY(90deg); left: -50%; }

        @keyframes globalRotate {
          from { transform: rotateY(0); }
          to { transform: rotateY(360deg); }
        }

        @keyframes ringRotate {
          from { transform: translate(-50%, -50%) rotateX(60deg) rotateZ(0); }
          to { transform: translate(-50%, -50%) rotateX(60deg) rotateZ(360deg); }
        }

        @keyframes orbitX { to { transform: translate(-50%, -50%) rotateX(75deg) rotateZ(360deg); } }
        @keyframes orbitY { to { transform: translate(-50%, -50%) rotateY(75deg) rotateZ(360deg); } }
        @keyframes orbitZ { to { transform: translate(-50%, -50%) rotateZ(75deg) rotateX(360deg); } }
      `}</style>
        </div>
    );
}

export default RoboticCore;
